   OSRTSAFEPUTCHAR_ZTERM (pctxt, ',');
   rtJsonEncIndent (pctxt);
   OSRTSAFEPUTCHAR_ZTERM (pctxt, '"');
   rtxCopyAsciiText (pctxt, "mME-Code");
   OSRTSAFEZTERM(pctxt);
   rtxCopyAsciiText (pctxt, "\":");
   OSRTSAFEZTERM(pctxt);
   stat = asn1JsonEnc_MME_Code (pctxt, &pvalue->mME_Code);
