   PU_NEWFIELD(pctxt, "extension bit");

   stat = rtxEncBit (pctxt, extbit);
   if (stat != 0) return LOG_RTERR (pctxt, stat);

   PU_SETBITCOUNT(pctxt);

   PU_NEWFIELD (pctxt, "m_eNB_UE_X2AP_IDPresent");

   stat = rtxEncBit (pctxt, (OSBOOL)pvalue->m.m_eNB_UE_X2AP_IDPresent);
   if (stat != 0) return LOG_RTERR (pctxt, stat);

   PU_SETBITCOUNT (pctxt);

   PU_NEWFIELD (pctxt, "m_eNB_UE_X2AP_ID_ExtensionPresent");

   stat = rtxEncBit (pctxt, (OSBOOL)pvalue->m.m_eNB_UE_X2AP_ID_ExtensionPresent);
